void solve(int CASE)
{
	ll n, q; cin >> n >> q;

	var to = vector<int>(n + 1);
	var w = vector<ll>(n + 1);
	fa(i, 1, n)cin >> to[i];
	fa(i, 1, n)cin >> w[i];

	var p = Vec2<int>(n + 1, 31); // 倍增父节点表
  	// dp[i][j]：从节点 i 开始，执行 2^j 次跳跃操作获得的信息
  	// 本题设的 dp 是 [i, 2^p) 的点权和 （2^p 代指 i 跳 2^p 步的祖先节点）
	var dp = Vec2<ll>(n + 1, 31);

	// 为何 dp[i][0] = w[i] 而不是 dp[i][0] = w[to[i]] ？
	// 一次操作：从 i 获得点权，然后跳到下一个点 to[i]
	// 在操作的过程中，产生贡献的是 i 不是 to[i]
	// 最后再把终点补上即可
	fa(i, 1, n) {
		p[i][0] = to[i];
		dp[i][0] = w[i];
	}

	// 初始化倍增
	fa(j, 1, 30) {
		fa(i, 1, n) {
			p[i][j] = p[p[i][j - 1]][j - 1];
          	// 根据本题的 dp 定义：
         	// dp[i][j] 的权值 = [i, 2^p) 的点权和
            //               = [i, 2^(p-1)) 的点权和 + [2^(p-1), 2^p) 的点权和
			dp[i][j] = dp[i][j - 1] + dp[p[i][j - 1]][j - 1];
		}
	}

	// 基环树上，从 now 开始走 k 步，求经过的点的点权和
	while (q--) {
		ll k, now; cin >> k >> now; // 从 now 开始，走 k 步，经过的点的点权和
		ll ans = 0;
		fa(i, 0, 30) {
			if (k & (1ll << i)) {
				ans += dp[now][i];
				now = p[now][i];
			}
		}
		ans += w[now]; // 再加上终点的权值
		cout << ans << endl;
	}
	return;
}

struct LCA {
    vector<int> depth;
    vector<vector<int>> f, mx;
    int LOG = 20;

    LCA(int n, const vector<int>& w, const vector<vector<int>>& g) {
        depth.resize(n + 1);
        f.assign(n + 1, vector<int>(LOG + 1));
        mx.assign(n + 1, vector<int>(LOG + 1));
        dfs(1, 0, w, g);
    }

    void dfs(int u, int p, const vector<int>& w, const vector<vector<int>>& g) {
        f[u][0] = p;
        mx[u][0] = w[u];               // 包括起点 u 的权值
        depth[u] = depth[p] + 1;
        for (int i = 1; i <= LOG; i++) {
            f[u][i] = f[f[u][i-1]][i-1];
            mx[u][i] = max(mx[u][i-1], mx[f[u][i-1]][i-1]);
        }
        for (int v : g[u]) if (v != p) dfs(v, u, w, g);
    }

    int query(int u, int v) {
        if (depth[u] < depth[v]) swap(u, v);

        int ans = 0;
        // 上升段：u 提到与 v 同深度
        for (int i = LOG; i >= 0; i--) {
            if (depth[u] - (1 << i) >= depth[v]) {
                ans = max(ans, mx[u][i]);
                u = f[u][i];
            }
        }
        if (u == v) return max(ans, mx[u][0]);   // 此时 u == v，已经包含 lca

        // 一起向上跳，直到 lca 的儿子
        for (int i = LOG; i >= 0; i--) {
            if (f[u][i] != f[v][i]) {
                ans = max({ans, mx[u][i], mx[v][i]});
                u = f[u][i];
                v = f[v][i];
            }
        }
        // 此时 u, v 是 lca 的两个直接儿子，lca = f[u][0]
        ans = max({ans, mx[u][0], mx[v][0], mx[f[u][0]][0]});
        return ans;
    }
};

