struct Info {
  	int sum;	      // 整个区间和
	int mxpre, mnpre; // 最大/最小前缀和
	int mxsuf, mnsuf; // 最大/最小后缀和
	int mxsub, mnsub; // 最大/最小子段和

	Info() :
		sum(0), 
		mxpre(0), mnpre(0), 
		mxsuf(0), mnsuf(0), 
		mxsub(0), mnsub(0)
	{}
	Info(int x) :
		sum(x), 
		mxpre(max(0, x)), mnpre(min(0, x)), 
		mxsuf(max(0, x)), mnsuf(min(0, x)), 
		mxsub(max(0, x)), mnsub(min(0, x))
	{}
};
Info operator+(const Info& lower, const Info& upper) {
	// 合并 下半段(lower) 和 上半段(upper)
	Info res;
	res.sum = lower.sum + upper.sum;
	res.mxpre = max(upper.mxpre, upper.sum + lower.mxpre);
	res.mnpre = min(upper.mnpre, upper.sum + lower.mnpre);
	res.mxsuf = max(lower.mxsuf, lower.sum + upper.mxsuf);
	res.mnsuf = min(lower.mnsuf, lower.sum + upper.mnsuf);
	res.mxsub = max({
		upper.mxsub, lower.mxsub,
		upper.sum + lower.mxpre - upper.mnpre,
		lower.sum + upper.mxsuf - lower.mnsuf
		});
	res.mnsub = min({
		upper.mnsub, lower.mnsub,
		upper.sum + lower.mnpre - upper.mxpre,
		lower.sum + upper.mnsuf - lower.mxsuf
		});
	return res;
}
var reverse = [](Info a)->Info {
	swap(a.mxpre, a.mxsuf);
	swap(a.mnpre, a.mnsuf);
